   362→	case errors.Is(err, context.DeadlineExceeded):
   363→		return status.Error(codes.DeadlineExceeded, err.Error())
   364→	case errors.Is(err, context.Canceled):
   365→		return status.Error(codes.Canceled, err.Error())
