    29→// EtcdManualResolver is a Resolver (and resolver.Builder) that can be updated
    30→// using SetEndpoints.
    31→type EtcdManualResolver struct {
    32→	*manual.Resolver
    33→	endpoints     []string
    34→	serviceConfig *serviceconfig.ParseResult
    35→}
    36→
    37→func New(endpoints ...string) *EtcdManualResolver {
    38→	r := manual.NewBuilderWithScheme(Schema)
    39→	return &EtcdManualResolver{Resolver: r, endpoints: endpoints, serviceConfig: nil}
    40→}
    41→
    42→// Build returns itself for Resolver, because it's both a builder and a resolver.
    43→func (r *EtcdManualResolver) Build(target resolver.Target, cc resolver.ClientConn, opts resolver.BuildOptions) (resolver.Resolver, error) {
    44→	r.serviceConfig = cc.ParseServiceConfig(`{"loadBalancingPolicy": "round_robin"}`)
    45→	if r.serviceConfig.Err != nil {
    46→		return nil, r.serviceConfig.Err
    47→	}
    48→	res, err := r.Resolver.Build(target, cc, opts)
    49→	if err != nil {
